ValidationRule.errorConditionFormula:
(
	(ISPICKVAL
		(leaseworks__Accrue_Interest_during_Grace_Period__c,'None')
	)
	&&
	(
		NOT(ISNULL
			( leaseworks__Grace_Period_Start_Date__c )
		) 
		||
		NOT(ISNULL
			( leaseworks__Grace_Period_End_Date__c )
		)
	)
)
||
(
	(
		(ISPICKVAL
			( leaseworks__Accrue_Interest_during_Grace_Period__c,'Yes')
		)
		||
		(ISPICKVAL
			( leaseworks__Accrue_Interest_during_Grace_Period__c,'No')
		)
	)
	&&
	(
		(
			(ISNULL
				( leaseworks__Grace_Period_Start_Date__c )
			)
		)
		||
		(
			(ISNULL
				( leaseworks__Grace_Period_End_Date__c )
			)
		)
	)
)
